import argparse, json, pickle, numpy as np, torch, warnings
from torchvision import transforms, models
from PIL import Image
from pathlib import Path
from tqdm import tqdm
import timm
from transformers import AutoModel

warnings.filterwarnings('ignore')
Image.MAX_IMAGE_PIXELS = None

T_DINO = transforms.Compose([
    transforms.Resize(224, interpolation=transforms.InterpolationMode.BICUBIC),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize([0.485,0.456,0.406],[0.229,0.224,0.225])
])
T_CLIP = transforms.Compose([
    transforms.Resize(224, interpolation=transforms.InterpolationMode.BICUBIC),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize([0.48145466,0.4578275,0.40821073],[0.26862954,0.26130258,0.27577711])
])
T_RESNET = transforms.Compose([
    transforms.Resize(256, interpolation=transforms.InterpolationMode.BILINEAR),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize([0.485,0.456,0.406],[0.229,0.224,0.225])
])

class DS(torch.utils.data.Dataset):
    def __init__(self, txt, root, tfm):
        self.root = Path(root)
        self.tfm = tfm
        with open(txt) as f:
            self.paths = [l.strip() for l in f if l.strip()]
    def __len__(self):
        return len(self.paths)
    def __getitem__(self, i):
        return self.tfm(Image.open(self.root / self.paths[i]).convert('RGB'))

@torch.no_grad()
def extract(model, loader, device, is_vit=False):
    model.eval()
    feats = []
    for x in tqdm(loader, desc='feat', mininterval=5):
        x = x.to(device)
        def fwd(t):
            y = model(t)
            if is_vit and hasattr(y, 'last_hidden_state'):
                return y.last_hidden_state[:, 0]
            return y.reshape(y.size(0), -1)
        y1 = fwd(x)
        y2 = fwd(torch.flip(x, dims=[3]))
        feats.append(((y1 + y2) * 0.5).cpu().numpy())
    return np.concatenate(feats, axis=0)

def normalize(x):
    return x / (np.linalg.norm(x, axis=1, keepdims=True) + 1e-8)

def infer_dim(obj):
    if hasattr(obj, 'coef_'):
        return obj.coef_.shape[1]
    if hasattr(obj, 'shape'):
        return obj.shape[-1]
    if isinstance(obj, list) and len(obj):
        return infer_dim(obj[0])
    if isinstance(obj, dict):
        if 'prototypes' in obj:
            return obj['prototypes'].shape[-1]
        if 'clfs' in obj and len(obj['clfs']):
            return infer_dim(obj['clfs'][0])
        if 'items' in obj and len(obj['items']):
            first = obj['items'][0]
            if isinstance(first, dict) and 'model' in first:
                return infer_dim(first['model'])
            return infer_dim(first)
    raise ValueError(f'Cannot infer dim from {type(obj)}')

def get_backbones(dim, device):
    need = set()
    if dim == 768:
        need = {'dinov2'}
    elif dim == 2048:
        need = {'resnet'}
    elif dim == 2816:
        need = {'dinov2', 'resnet'}
    elif dim == 3584:
        need = {'dinov2', 'resnet', 'clip'}
    else:
        raise ValueError(f'Unknown dim {dim}')
    backbones = {}
    if 'dinov2' in need:
        m = AutoModel.from_pretrained('facebook/dinov2-base')
        m.eval().to(device)
        backbones['dinov2'] = (m, True)
    if 'resnet' in need:
        m = models.resnet50(weights='IMAGENET1K_V2')
        m = torch.nn.Sequential(*list(m.children())[:-1])
        m.eval().to(device)
        backbones['resnet'] = (m, False)
    if 'clip' in need:
        m = timm.create_model('vit_base_patch16_clip_224.openai', pretrained=True, num_classes=0)
        m.eval().to(device)
        backbones['clip'] = (m, True)
    return backbones

def extract_all(data_path, backbones, device):
    txt = Path(data_path) / 'test.txt'
    img_root = Path(data_path) / 'images'
    feats = {}
    for name, (model, is_vit) in backbones.items():
        tfm = {'dinov2': T_DINO, 'clip': T_CLIP, 'resnet': T_RESNET}[name]
        ds = DS(txt, img_root, tfm)
        loader = torch.utils.data.DataLoader(ds, batch_size=64, shuffle=False, num_workers=2, pin_memory=True)
        feats[name] = normalize(extract(model, loader, device, is_vit))
    return feats

def assemble(feats, dim):
    parts = []
    if dim in (768, 2816, 3584):
        parts.append(feats['dinov2'])
    if dim in (2048, 2816, 3584):
        parts.append(feats['resnet'])
    if dim == 3584:
        parts.append(feats['clip'])
    return np.concatenate(parts, axis=1)

def get_logits(ckpt, X):
    if hasattr(ckpt, 'decision_function'):
        return ckpt.decision_function(X)
    if hasattr(ckpt, 'predict_proba'):
        p = ckpt.predict_proba(X)
        eps = 1e-8
        return np.log(np.clip(p, eps, 1 - eps))
    raise ValueError(f'Cannot get logits from {type(ckpt)}')

def predict_proba_ckpt(ckpt, X):
    if hasattr(ckpt, 'predict_proba'):
        return ckpt.predict_proba(X)
    if hasattr(ckpt, 'decision_function'):
        logits = ckpt.decision_function(X)
        e = np.exp(logits - np.max(logits, axis=1, keepdims=True))
        return e / e.sum(axis=1, keepdims=True)
    if isinstance(ckpt, list):
        probs = np.zeros((X.shape[0], 10))
        for clf in ckpt:
            probs += predict_proba_ckpt(clf, X)
        return probs / len(ckpt)
    if isinstance(ckpt, dict):
        if 'items' in ckpt:
            probs = None
            for item in ckpt['items']:
                w = item.get('weight', 1.0)
                m = item['model']
                p = predict_proba_ckpt(m, X) * w
                if probs is None:
                    probs = p
                else:
                    probs += p
            return probs
        if 'clfs' in ckpt:
            logits = np.mean([get_logits(c, X) for c in ckpt['clfs']], axis=0)
            bias = ckpt.get('bias', 0)
            if isinstance(bias, np.ndarray):
                logits = logits + bias
            e = np.exp(logits - np.max(logits, axis=1, keepdims=True))
            return e / e.sum(axis=1, keepdims=True)
        if 'prototypes' in ckpt:
            protos = ckpt['prototypes']
            n_d, n_c, dim = protos.shape
            scores = np.zeros((X.shape[0], n_c))
            for d in range(n_d):
                s = X @ protos[d].T
                e = np.exp(s - np.max(s, axis=1, keepdims=True))
                scores += e / e.sum(axis=1, keepdims=True)
            return scores / n_d
    raise ValueError(f'Unsupported checkpoint type: {type(ckpt)}')

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    ckpt = pickle.load(open(args.checkpoint, 'rb'))

    dim = infer_dim(ckpt)
    backbones = get_backbones(dim, device)
    feats = extract_all(args.data_path, backbones, device)
    X = assemble(feats, dim)

    probs = predict_proba_ckpt(ckpt, X)
    preds = np.argmax(probs, axis=1).tolist()

    with open(args.output, 'w') as f:
        json.dump({'predictions': preds}, f)

if __name__ == '__main__':
    main()
